import { useEffect, useState } from 'react';
import api from '../../api/client';

export default function MasterCrudPage({
  title,
  apiPath,
  fields,
  primaryField,
}) {
  const [items, setItems] = useState([]);
  const [form, setForm] = useState({});
  const [editingId, setEditingId] = useState(null);

  const loadItems = async () => {
    try {
      const res = await api.get(apiPath);
      setItems(Array.isArray(res.data) ? res.data : res.data.results || []);
    } catch (err) {
      console.error(`Failed to load ${title}`, err);
    }
  };

  useEffect(() => {
    const initial = {};
    fields.forEach((f) => {
      initial[f.name] = '';
    });
    setForm(initial);
    loadItems();
  }, [apiPath]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const normalizePayload = () => {
  const payload = { ...form };

  Object.keys(payload).forEach((key) => {
    if (payload[key] === '') {
      payload[key] = null;
    }
  });

  ['is_active', 'use_tls', 'use_ssl'].forEach((key) => {
    if (key in payload) {
      if (payload[key] === 'true' || payload[key] === true) payload[key] = true;
      else if (payload[key] === 'false' || payload[key] === false) payload[key] = false;
    }
  });

  ['module', 'smtp_port'].forEach((key) => {
    if (key in payload && payload[key] !== null && payload[key] !== undefined) {
      payload[key] = Number(payload[key]);
    }
  });

  if (editingId && title === 'Email Configs' && !payload.smtp_password) {
    delete payload.smtp_password;
  }

  return payload;
};

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const payload = normalizePayload();

      if (editingId) {
        await api.put(`${apiPath}${editingId}/`, payload);
      } else {
        await api.post(apiPath, payload);
      }

      setEditingId(null);

      const reset = {};
      fields.forEach((f) => {
        reset[f.name] = '';
      });
      setForm(reset);

      loadItems();
    } catch (err) {
      console.error(`Failed to save ${title}`, err);
      alert(`Failed to save ${title}`);
    }
  };

  const handleEdit = (item) => {
    setEditingId(item.id);
    const updated = {};
    fields.forEach((f) => {
      updated[f.name] = item[f.name] ?? '';
    });
    setForm(updated);
  };

  const handleDelete = async (id) => {
    try {
      await api.delete(`${apiPath}${id}/`);
      loadItems();
    } catch (err) {
      console.error(`Failed to delete ${title}`, err);
      alert(`Failed to delete ${title}`);
    }
  };

  const renderInput = (field) => {
  if (
    field.name === 'is_active' ||
    field.name === 'use_tls' ||
    field.name === 'use_ssl'
  ) {
    return (
      <select
        className="form-select"
        name={field.name}
        value={form[field.name] ?? ''}
        onChange={handleChange}
      >
        <option value="">Select</option>
        <option value="true">True</option>
        <option value="false">False</option>
      </select>
    );
  }

  return (
    <input
      className="form-control"
      name={field.name}
      value={form[field.name] ?? ''}
      onChange={handleChange}
    />
  );
};

  return (
    <div className="card mb-4">
      <div className="card-body">
        <h4 className="mb-3">{title}</h4>

        <form className="row g-3 mb-4" onSubmit={handleSubmit}>
          {fields.map((field) => (
            <div className="col-md-4" key={field.name}>
              <label className="form-label">{field.label}</label>
              {renderInput(field)}
            </div>
          ))}

          <div className="col-12">
            <button className="btn btn-primary me-2" type="submit">
              {editingId ? 'Update' : 'Add'}
            </button>
            <button
              className="btn btn-secondary"
              type="button"
              onClick={() => {
                setEditingId(null);
                const reset = {};
                fields.forEach((f) => {
                  reset[f.name] = '';
                });
                setForm(reset);
              }}
            >
              Clear
            </button>
          </div>
        </form>

        <div className="table-responsive">
          <table className="table table-bordered">
            <thead>
              <tr>
                <th>ID</th>
                <th>{primaryField}</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {items.length ? (
                items.map((item) => (
                  <tr key={item.id}>
                    <td>{item.id}</td>
                    <td>{item[fields[0].name]}</td>
                    <td>
                      <button
                        className="btn btn-sm btn-warning me-2"
                        onClick={() => handleEdit(item)}
                      >
                        Edit
                      </button>
                      <button
                        className="btn btn-sm btn-danger"
                        onClick={() => handleDelete(item.id)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="3">No data found</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
